import{_ as t,o as s,c as o,a2 as n}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"RFC 0018 — Plugin-scoped environment variables","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0018-plugin-scoped-env.md","filePath":"rfcs/0018-plugin-scoped-env.md"}'),i={name:"rfcs/0018-plugin-scoped-env.md"};function a(r,e,d,l,c,p){return s(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="rfc-0018-—-plugin-scoped-environment-variables" tabindex="-1">RFC 0018 — Plugin-scoped environment variables <a class="header-anchor" href="#rfc-0018-—-plugin-scoped-environment-variables" aria-label="Permalink to &quot;RFC 0018 — Plugin-scoped environment variables&quot;">​</a></h1><p><strong>Status:</strong> Accepted<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>packages/manifest</code> (new optional <code>env</code> field), <code>packages/sdk</code> (<code>sdk.env</code> scoped accessor), <code>scripts/generate-registry.ts</code> (merge + namespacing + validation), the runtime env loader, <code>.env.example</code> / <code>docs/self-hosting.md</code> / <code>docs/plugin-development.md</code> + the docs-parity tests, Docker/Compose; builds on the plugin model (SRS §3.5/§3.9) and RFC 0008 (secret handling)<br><strong>Incorporated into plan:</strong> Yes — scheduled as roadmap Task 0.5.23; documentation-first. This RFC specifies the model for plugin-declared environment variables and the end-to-end flows; SRS requirement IDs, scheduling, and task allocation are deferred.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Let a plugin declare and supply its <strong>own</strong> environment variables — entirely within the plugin&#39;s scope, without ever editing the root <code>.env</code> or any other monorepo file — and have the platform incorporate them safely. The design rests on two pillars:</p><ul><li><strong>Three distinct value sources</strong>, separating what can be shipped from what must not: developer-shipped <strong>non-secret defaults</strong> (baked), the developer&#39;s <strong>local dev values</strong> (never shipped), and the operator&#39;s <strong>production secrets</strong> (injected at runtime, never baked).</li><li><strong>Auto-namespacing</strong>: every plugin key lives in the shared runtime environment as <code>SV_PLUGIN_&lt;SLUG&gt;_&lt;KEY&gt;</code>; the plugin reads its own keys <strong>unprefixed</strong> through a scoped SDK accessor (<code>sdk.env.get(&#39;KEY&#39;)</code>), so a plugin can neither collide with platform variables nor with another plugin.</li></ul><p>The guiding constraint: <strong>secret values are never written into shipped artifacts.</strong> &quot;Incorporate keys and values into the build&quot; applies to non-secret config; sensitive values are supplied by the operator at deploy time.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Sovereign loads a single <strong>root <code>.env</code></strong> shared by the runtime and auth apps. A plugin that needs its own configuration — an upstream API base URL, a feature flag, a third-party API key — has no sanctioned channel today: it would have to edit the root <code>.env</code> or other monorepo files, which it must never do (plugins are external, gitignored, composed as copies). Plugins need a first-class way to carry their configuration in their own repository and have the platform pick it up — including a clear, safe answer for <strong>sensitive values</strong>, which a plugin author cannot ship (they differ per deployment and belong to the operator).</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>Single root <code>.env</code>, shared.</strong> <code>runtime/next.config.ts</code> and <code>apps/auth/next.config.ts</code> call <code>@next/env</code> <code>loadEnvConfig</code> against the monorepo root before the app boots; both apps read the same file. There are no per-app or per-plugin <code>.env</code> files today.</li><li><strong>Two Next.js env tiers.</strong> <code>NEXT_PUBLIC_*</code> is <strong>inlined into the client bundle at build time</strong> (baked, public, immutable after build); everything else is read at <strong>runtime</strong> from <code>process.env</code>.</li><li><strong>Artifacts keep env out.</strong> <code>.dockerignore</code> strips <code>.env</code>; the production standalone server reads env from the Compose <code>environment:</code> block at <strong>container start</strong> (e.g. <code>runtime/middleware.ts:14</code> reads <code>SOVEREIGN_AUTH_URL</code> at request time). Baking secret values into the image is both a regression and a hazard.</li><li><strong>Plugins share the runtime process.</strong> Native plugin <code>app/</code> trees are <strong>copied</strong> into the runtime and run in the same Node process — they read the <strong>same</strong><code>process.env</code> as the platform (e.g. the Console plugin reads <code>process.env.SOVEREIGN_ADMIN_KEY</code>). → collision risk and, today, unrestricted read of platform variables.</li><li><strong><code>generate-registry.ts</code> runs before <code>next build</code></strong> (and re-runs in dev), validating manifests and copying plugin trees in — the natural injection point.</li><li><strong>Manifest is <code>.strict()</code> with docs-parity.</strong> Adding an <code>env</code> field is an additive <strong>minor</strong> <code>@sovereignfs/manifest</code> bump; <code>manifestFieldNames</code> + <code>runtime/src/docs-parity.test.ts</code> enforce that every field is documented.</li><li><strong>No-default-secrets rule.</strong> <code>apps/auth/src/env.ts</code> <code>required()</code> throws on a missing secret rather than defaulting — the pattern plugin secrets reuse.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="the-three-value-sources-the-core-model" tabindex="-1">The three value sources (the core model) <a class="header-anchor" href="#the-three-value-sources-the-core-model" aria-label="Permalink to &quot;The three value sources (the core model)&quot;">​</a></h3><p>The central move is to <strong>stop treating &quot;plugin env&quot; as one thing.</strong> There are three sources with different trust and lifecycle:</p><ol><li><strong>Developer-shipped non-secret defaults</strong> — declared in the <strong>manifest</strong> (<code>env[KEY].default</code>). Committed to the plugin repo, validated, and <strong>baked</strong> into the build. This is the &quot;values in build artifacts&quot; case, made safe by construction: <code>default</code> is <strong>rejected on <code>secret: true</code> keys</strong>, so only non-secret config is ever baked.</li><li><strong>Developer local dev/test values</strong> — a <strong>gitignored plugin-local <code>.env</code></strong> in <code>plugins/&lt;id&gt;/</code> (plugin scope, never shipped, loaded only in dev). Lets a developer test with real values — including their own throwaway secrets — without editing the root <code>.env</code>.</li><li><strong>Operator production secrets</strong> — supplied at deploy time via the <strong>namespaced container env</strong> (<code>SV_PLUGIN_&lt;SLUG&gt;_&lt;KEY&gt;</code>). Declared <code>secret: true</code> / <code>required</code> in the manifest; <strong>validated present at startup</strong> (fail-fast, no default); <strong>never baked</strong> into any artifact.</li></ol><p>This reconciles &quot;plugin developers pass values&quot; (sources 1–2) with secret-safety (source 3 owns the sensitive values the developer cannot know).</p><h3 id="manifest-env-field" tabindex="-1">Manifest <code>env</code> field <a class="header-anchor" href="#manifest-env-field" aria-label="Permalink to &quot;Manifest \`env\` field&quot;">​</a></h3><p>An optional declaration map — the plugin&#39;s env <strong>contract</strong>:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;API_BASE_URL&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Upstream API base URL.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;scope&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// non-secret, eligible for client inlining</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;default&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://api.example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;API_KEY&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Upstream API key.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;required&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;secret&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// implies runtime scope; operator-supplied; never baked</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Rules: <code>default</code> is allowed <strong>only</strong> when <code>!secret</code>; <code>scope: &#39;build&#39;</code> marks non-secret public config (client-inlinable); <code>secret</code> implies <code>scope: &#39;runtime&#39;</code>. Additive optional field → manifest <strong>minor</strong> bump; <code>manifestFieldNames</code> + docs-parity updated.</p><h3 id="auto-namespacing-the-sdk-env-accessor" tabindex="-1">Auto-namespacing + the <code>sdk.env</code> accessor <a class="header-anchor" href="#auto-namespacing-the-sdk-env-accessor" aria-label="Permalink to &quot;Auto-namespacing + the \`sdk.env\` accessor&quot;">​</a></h3><p>The platform maps every declared key into the shared environment as <code>SV_PLUGIN_&lt;SLUG&gt;_&lt;KEY&gt;</code>, so a plugin can never clobber a platform variable or another plugin&#39;s. The plugin reads its <strong>own</strong> keys unprefixed:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> base</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sdk.env.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;API_BASE_URL&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// resolves SV_PLUGIN_&lt;SLUG&gt;_API_BASE_URL</span></span></code></pre></div><p>For <code>scope: &#39;build&#39;</code> public values that must reach the <strong>client</strong>, the platform emits a <code>NEXT_PUBLIC_SV_PLUGIN_&lt;SLUG&gt;_&lt;KEY&gt;</code> form so <code>next build</code> inlines it, and a client-safe <code>sdk.env</code> reads those.</p><p><strong>Honest limitation:</strong> because plugins run in the runtime&#39;s process, true <em>read isolation</em> — preventing a plugin from reading <code>process.env</code> directly — is <strong>not enforceable</strong> in v1. Namespacing prevents <em>collision</em>, and <code>sdk.env</code> is the sanctioned, ergonomic, plugin-scoped path; deeper sandboxing (separate processes / a vetting model) is a non-goal here and is left to a future RFC.</p><h3 id="build-inject-pipeline" tabindex="-1">Build / inject pipeline <a class="header-anchor" href="#build-inject-pipeline" aria-label="Permalink to &quot;Build / inject pipeline&quot;">​</a></h3><p><code>generate-registry.ts</code> becomes the single incorporation point. For each plugin it:</p><ol><li>reads the manifest <code>env</code> declarations + the plugin-local <code>.env</code> (dev only);</li><li><strong>namespaces</strong> keys to <code>SV_PLUGIN_&lt;SLUG&gt;_&lt;KEY&gt;</code>;</li><li>writes a <strong>generated, gitignored</strong> consolidated module/file (<code>runtime/generated/plugin-env.*</code>) the loader merges into the environment, and emits the <code>NEXT_PUBLIC_*</code> forms for <code>scope: &#39;build&#39;</code> keys so they inline;</li><li><strong>validates</strong> — required keys are declared, <strong>no <code>default</code> on a <code>secret</code> key</strong>, no collision with platform-reserved keys, and the plugin has <strong>not</strong> shipped a value for a <code>secret</code> key (a committed secret value fails the build).</li></ol><p>Secret keys are <strong>never</strong> written to the generated file or the image — they are required from the <strong>container env</strong> at start. The step already runs in the Docker <strong>builder</strong> stage, so non-secret defaults reach the image while secrets stay external (delivered via Compose <code>environment:</code> at container start, same as platform secrets).</p><h3 id="operator-experience" tabindex="-1">Operator experience <a class="header-anchor" href="#operator-experience" aria-label="Permalink to &quot;Operator experience&quot;">​</a></h3><p>The generate step also emits a consolidated, <code>.env.example</code>-style <strong>list of operator-supplied keys</strong> (the <code>required</code>/<code>secret</code> ones, already namespaced) so the operator knows exactly what to set. This is surfaced in <code>docs/self-hosting.md</code> and, optionally, a Console &quot;plugin configuration&quot; view (open question). The env docs-parity concept extends to plugin-declared keys so operator-facing config can&#39;t drift undocumented.</p><h2 id="ui-flows" tabindex="-1">UI / flows <a class="header-anchor" href="#ui-flows" aria-label="Permalink to &quot;UI / flows&quot;">​</a></h2><p><strong>Developer</strong> — declares keys (+ non-secret <code>default</code>s) in the manifest <code>env</code>; reads them via <code>sdk.env.get(&#39;KEY&#39;)</code>; for local testing puts real values in a gitignored <code>plugins/&lt;id&gt;/.env</code>. Ships the plugin with <strong>no secret values</strong> in it.</p><p><strong>Operator</strong> — installs the plugin, sees the generated list of required <code>SV_PLUGIN_&lt;SLUG&gt;_*</code> secret keys, sets them in their deploy env (Compose <code>environment:</code> / orchestrator). On startup the platform validates the required secrets are present (fail-fast) and exposes each plugin&#39;s keys to it, namespaced.</p><p><strong>Build</strong> — non-secret defaults + <code>scope: &#39;build&#39;</code> public values are baked/inlined; secrets are absent from the artifact and read at container start.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Bake everything (keys + values, incl. secrets).</strong> Simplest, but ships secrets inside the image — and any <code>NEXT_PUBLIC_*</code> secret into client JS for everyone to read. Rejected; the three-source split exists precisely to avoid this.</li><li><strong>Manifest keys-only, no developer-supplied values.</strong> Clean, but doesn&#39;t satisfy &quot;plugin developers pass values&quot; — a plugin couldn&#39;t ship sensible non-secret defaults. Rejected in favour of <code>default</code> (non-secret only).</li><li><strong>Per-plugin process isolation for a true env sandbox.</strong> Would give real read isolation, but it is not how the in-process, composed-copy runtime works in v1. Rejected for now; noted as a possible future direction.</li><li><strong>Convention-only namespacing.</strong> Rejected per the design decision — auto- namespacing is enforced so a careless or malicious plugin can&#39;t shadow platform variables.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Namespace token</strong> — <code>SV_PLUGIN_&lt;SLUG&gt;_</code> vs an alternative; how the <code>&lt;SLUG&gt;</code> is derived from the plugin <code>id</code>.</li><li><strong>Operator config surface</strong> — a Console &quot;plugin configuration&quot; view for required secrets, or docs/generated-example only?</li><li><strong><code>NEXT_PUBLIC_</code> rebuild caveat</strong> — <code>scope: &#39;build&#39;</code> public values are baked, so changing one needs a rebuild; is that acceptable, or do some &quot;public&quot; values want a runtime path?</li><li><strong>At-rest interaction</strong> — if operator secrets are ever stored (vs read from env), how that intersects RFC 0008&#39;s at-rest encryption.</li><li><strong><code>sdk.env</code> semantics</strong> — exact behaviour in server vs client components.</li><li><strong>Requirement IDs</strong> — proposed entries, deferred until accepted.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>Documentation-first (this RFC).</strong> Model + flows captured; no code, no SRS edits, no scheduling.</li><li><strong>When accepted &amp; scheduled:</strong> the manifest <code>env</code> field (manifest <strong>minor</strong>), the <code>generate-registry.ts</code> merge + namespacing + validation, the generated consolidated loader file, the <code>sdk.env</code> scoped accessor (additive SDK <strong>minor</strong>), and the <code>.env.example</code> / <code>docs/self-hosting.md</code> / <code>docs/plugin-development.md</code> + docs-parity updates.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; plugin-declared env via a manifest <code>env</code> field, three value sources (baked non-secret defaults / dev-local / operator-supplied secrets), auto-namespacing + <code>sdk.env</code>, secrets never baked; documentation-first.</td></tr><tr><td>0.2</td><td>Jun 2026</td><td>Accepted; scheduled in the roadmap as Task 0.5.23.</td></tr></tbody></table>`,43)])])}const u=t(i,[["render",a]]);export{g as __pageData,u as default};
